package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonIOException;
import com.google.gson.JsonSyntaxException;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import com.google.gson.stream.MalformedJsonException;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

class GsonAssertFullConsumptionTest {

    private static void invokeAssertFullConsumption(Object obj, JsonReader reader) throws Throwable {
        Method method = Gson.class.getDeclaredMethod("assertFullConsumption", Object.class, JsonReader.class);
        method.setAccessible(true);
        try {
            method.invoke(null, obj, reader);
        } catch (InvocationTargetException e) {
            throw e.getCause();
        }
    }

    @Test
    public void testNullObjectDoesNotThrow() throws Throwable {
        JsonReader reader = mock(JsonReader.class);

        // obj is null, should not throw and peek should not be called
        assertDoesNotThrow(() -> invokeAssertFullConsumption(null, reader));
        verify(reader, never()).peek(); // peek should not be called if obj is null
    }

    @Test
    public void testObjectWithEndDocumentDoesNotThrow() throws Throwable {
        JsonReader reader = mock(JsonReader.class);
        when(reader.peek()).thenReturn(JsonToken.END_DOCUMENT);

        Object obj = new Object();
        // obj not null but reader.peek() is END_DOCUMENT, no exception
        assertDoesNotThrow(() -> invokeAssertFullConsumption(obj, reader));
        verify(reader).peek();
    }

    @Test
    public void testObjectWithNonEndDocumentThrowsJsonSyntaxException() throws Throwable {
        JsonReader reader = mock(JsonReader.class);
        when(reader.peek()).thenReturn(JsonToken.BEGIN_ARRAY);

        Object obj = new Object();
        JsonSyntaxException ex = assertThrows(JsonSyntaxException.class, () -> invokeAssertFullConsumption(obj, reader));
        assertEquals("JSON document was not fully consumed.", ex.getMessage());
        verify(reader).peek();
    }

    @Test
    public void testMalformedJsonExceptionWrappedAsJsonSyntaxException() throws Throwable {
        JsonReader reader = mock(JsonReader.class);
        when(reader.peek()).thenThrow(new MalformedJsonException("malformed"));

        Object obj = new Object();
        JsonSyntaxException ex = assertThrows(JsonSyntaxException.class, () -> invokeAssertFullConsumption(obj, reader));
        assertTrue(ex.getCause() instanceof MalformedJsonException);
        assertEquals("malformed", ex.getCause().getMessage());
        verify(reader).peek();
    }

    @Test
    public void testIOExceptionWrappedAsJsonIOException() throws Throwable {
        JsonReader reader = mock(JsonReader.class);
        when(reader.peek()).thenThrow(new IOException("io failure"));

        Object obj = new Object();
        JsonIOException ex = assertThrows(JsonIOException.class, () -> invokeAssertFullConsumption(obj, reader));
        assertTrue(ex.getCause() instanceof IOException);
        assertEquals("io failure", ex.getCause().getMessage());
        verify(reader).peek();
    }
}
